mapper.select:
select id, content, user_id, reply_count, like_count, updated_at from video_user_comment where video_id = #{videoId} and parent_id is NULL
and id < #{lastMinId}
order by id desc limit 8

select a.id, a.content, a.user_id as senderId, b.user_id as receiverId, a.parent_id, a.reply_count, a.like_count, a.updated_at from video_user_comment a join video_user_comment b on a.parent_id = b.id where a.root_id = #{commentId}
and a.id > #{lastMaxId}
order by a.id limit 8
